1126	/// Render one grouped table into `out`. Column widths are computed across
1127	/// every row (so headers line up across category groups within the table)
1128	/// but independent of any other table. When `include_group_summary` is
1129	/// true, append a `Group: <category> — N ri_better / ...` line under each
1130	/// category's rows.
1131	fn render_grouped_table(
1132	    headers: &[&str],
1133	    rows: &[(Option<TaskCategory>, &AgentEvalComparison, Vec<String>)],
1134	    category_order: &[Option<TaskCategory>],
1135	    include_group_summary: bool,
1136	    out: &mut Vec<String>,
1137	) {
1138	    let n = headers.len();
1139	    let mut widths: Vec<usize> = headers.iter().map(|h| h.len()).collect();
1140	    for (_, _, cells) in rows {
1141	        for (i, cell) in cells.iter().enumerate() {
1142	            if i < n {
1143	                widths[i] = widths[i].max(cell.chars().count());
1144	            }
1145	        }
1146	    }
1147	    let render = |cells: &[String]| -> String {
1148	        cells
1149	            .iter()
1150	            .enumerate()
1151	            .map(|(i, cell)| {
1152	                let pad = widths.get(i).copied().unwrap_or(0);
1153	                let cell_len = cell.chars().count();
1154	                let extra = pad.saturating_sub(cell_len);
1155	                format!("{cell}{}", " ".repeat(extra))
1156	            })
1157	            .collect::<Vec<_>>()
1158	            .join(" | ")
1159	    };
1160	    let header_cells: Vec<String> = headers.iter().map(|h| h.to_string()).collect();
1161	    let separator_cells: Vec<String> = widths.iter().map(|w| "-".repeat(*w)).collect();
1162	
1163	    for category in category_order {
1164	        let group: Vec<&(Option<TaskCategory>, &AgentEvalComparison, Vec<String>)> =
1165	            rows.iter().filter(|(c, _, _)| c == category).collect();
1166	        if group.is_empty() {
1167	            continue;
1168	        }
1169	        let category_label = category.map_or("uncategorized", TaskCategory::slug);
1170	        out.push(String::new());
1171	        out.push(format!("== {category_label} =="));
1172	        out.push(render(&header_cells));
1173	        out.push(render(&separator_cells));
1174	        for (_, _, cells) in &group {
1175	            out.push(render(cells));
1176	        }
1177	        if include_group_summary {
1178	            out.push(format!(
1179	                "Group: {category_label} — {}",
1180	                group_summary(group.iter().map(|(_, row, _)| *row)),
1181	            ));
1182	        }
1183	    }
1184	}
