1186	/// Count `result` outcomes across a slice of comparisons and emit a one-line
1187	/// summary like `2 ri_better / 0 ri_worse / 1 tie / 0 excluded`.
1188	fn group_summary<'a>(rows: impl IntoIterator<Item = &'a AgentEvalComparison>) -> String {
1189	    let mut better = 0u32;
1190	    let mut worse = 0u32;
1191	    let mut tie = 0u32;
1192	    let mut excluded = 0u32;
1193	    for row in rows {
1194	        match row.result {
1195	            AgentEvalResult::RiBetter { .. } => better += 1,
1196	            AgentEvalResult::RiWorse { .. } => worse += 1,
1197	            AgentEvalResult::Tie => tie += 1,
1198	            AgentEvalResult::Excluded { .. } => excluded += 1,
1199	        }
1200	    }
1201	    format!("{better} ri_better / {worse} ri_worse / {tie} tie / {excluded} excluded")
1202	}
